docker_compose:
services:
  wakapi:
    image: ghcr.io/muety/wakapi:latest
    environment:
      - TZ=${TIMEZONE:-Europe/Berlin}
      - WAKAPI_SERVER_LISTEN_IPV6="-"
      - WAKAPI_ENV=${WAKAPI_ENVIRONMENT:-production}
      - WAKAPI_SECURITY_PASSWORD_SALT=Y2QwYjQ2MGY5NjkxZjczMjY4NTZlYzg1
      - WAKAPI_SECURITY_EXPOSE_METRICS=${WAKAPI_SECURITY_EXPOSE_METRICS:-false}
      - WAKAPI_DB_TYPE=postgres
      - WAKAPI_DB_NAME=${WAKAPI_DB_NAME:-wakapi}
      - WAKAPI_DB_USER=ub5c172164c
      - WAKAPI_DB_PASSWORD=f68ed2c8b677ebe822e7296d4d685884
      - WAKAPI_DB_HOST=${WAKAPI_DB_HOST:-postgres}
      - WAKAPI_DB_PORT=${WAKAPI_DB_PORT:-5432}
      - WAKAPI_MAIL_ENABLED=${WAKAPI_MAIL_ENABLED:-false}
      - WAKAPI_MAIL_PROVIDER=smtp
      - WAKAPI_MAIL_SENDER=${WAKAPI_MAIL_SENDER}
      - WAKAPI_MAIL_SMTP_HOST=${WAKAPI_MAIL_SMTP_HOST}
      - WAKAPI_MAIL_SMTP_PORT=${WAKAPI_MAIL_SMTP_PORT:-587}
      - WAKAPI_MAIL_SMTP_USER=${WAKAPI_MAIL_SMTP_USERNAME:-liv8bcdbe9d}
      - WAKAPI_MAIL_SMTP_PASS=${WAKAPI_MAIL_SMTP_PASSWORD:-baa1e37dbd824d80270e2fc35a8aa1e3}
      - WAKAPI_MAIL_SMTP_TLS=${WAKAPI_MAIL_SMTP_TLS:-true}
      - WAKAPI_ALLOW_SIGNUP=${WAKAPI_ALLOW_SIGNUP:-true}
      - WAKAPI_LEADERBOARD_ENABLED=${WAKAPI_LEADERBOARD_ENABLED:-true}
      - WAKAPI_DISABLE_FRONTPAGE=${WAKAPI_DISABLE_FRONTPAGE:-true}
      - WAKAPI_PUBLIC_URL=${WAKAPI_PUBLIC_URL}
    volumes:
      - wakapi-data:/data
    depends_on:
      postgres:
        condition: service_healthy
    healthcheck:
      test:
        - CMD-SHELL
        - wget -qO- http://127.0.0.1:3000/
      interval: 2s
      timeout: 10s
      retries: 15
    restart: unless-stopped
    ports:
      - 42138:3000
  postgres:
    image: postgres:16-alpine
    volumes:
      - wakapi-postgres-data:/var/lib/postgresql/data
    environment:
      - POSTGRES_USER=ub5c172164c
      - POSTGRES_PASSWORD=f68ed2c8b677ebe822e7296d4d685884
      - POSTGRES_DB=${WAKAPI_DB_NAME:-wakapi}
      - POSTGRES_PORT=${WAKAPI_DB_PORT:-5432}
    healthcheck:
      test:
        - CMD-SHELL
        - pg_isready -U $${POSTGRES_USER:-livcf4e0dc0} -d $${POSTGRES_DB:-wakapi}
      interval: 5s
      timeout: 20s
      retries: 10
    restart: unless-stopped
volumes:
  wakapi-data: null
  wakapi-postgres-data: null
